# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple. Follow security best practices.
# Category: csrf

from flask import Flask, request, jsonify, session
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your_secret_key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///database.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)
    two_factor_enabled = db.Column(db.Boolean, default=False)

@app.route('/profile', methods=['POST'])
def update_profile():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    two_factor_enabled = data.get('two_factor_enabled')

    user = User.query.filter_by(email=session['email']).first()

    if email:
        user.email = email

    if password:
        user.password = generate_password_hash(password)

    if two_factor_enabled is not None:
        user.two_factor_enabled = two_factor_enabled

    db.session.commit()

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)